import { useState } from "react";

const CabinGallery = ({ photos }) => {
  const [active, setActive] = useState(0);

  return (
    <div className="w-[50%]">
      <img
        src={photos[active]}
        className="w-full h-[55vh] object-cover rounded-[12px]"
      />

      <div className="flex gap-3 mt-4 overflow-hidden">
        {photos.map((photo, index) => (
          <img
            key={index}
            src={photo}
            className="w-[35vh] h-[15vh] cursor-pointer rounded-[8px]"
            onClick={() => setActive(index)}
          />
        ))}
      </div>
    </div>
  );
};

export default CabinGallery;
